// Fuzzy matching for installed mod names
const ALIASES = {
  'bepinex with configuration manager':'Pre-configured BepInEx with Configuration Manager',
  'fast opening pack':'Fast Pack Opening V2',
};
const normalize = (n) => (n||'').replace(/\s*v?\d+(\.\d+)*\s*$/i,'').replace(/^[oO]?\d+\s+/,'').replace(/([a-z])([A-Z])/g,'$1 $2').replace(/[-_]+/g,' ').replace(/\s+/g,' ').toLowerCase().trim();

export function I18nProvider({ children, locale: initialLocale }) {
  const [locale, setLocale] = useState(initialLocale || 'en');

  const t = (key) => {
    if (!key || locale === 'en') return key;
    return UI[locale]?.[key] || UI[locale.split('-')[0]]?.[key] || key;
  };

  const tMod = (name, desc) => {
    if (locale === 'en') return { name, description: desc };
    const lang = MODS[locale] || MODS[locale.split('-')[0]];
    if (!lang) return { name, description: desc };
    if (lang[name]) return { name: lang[name][0], description: lang[name][1] };
    const norm = normalize(name);
    const aliased = ALIASES[norm];
    if (aliased && lang[aliased]) return { name: lang[aliased][0], description: lang[aliased][1] };
    for (const key of Object.keys(lang)) {
      if (normalize(key) === norm) return { name: lang[key][0], description: lang[key][1] };
    }
    for (const key of Object.keys(lang)) {
      const nk = normalize(key);
      if (nk.length > 3 && (norm.includes(nk) || nk.includes(norm))) return { name: lang[key][0], description: lang[key][1] };
    }
    return { name, description: desc };
  };

  return <I18nContext.Provider value={{ locale, setLocale, t, tMod }}>{children}</I18nContext.Provider>;
}

export function useI18n() { return useContext(I18nContext); }

export const SUPPORTED_LOCALES = [
  { code:'en', label:'English' },{ code:'es', label:'Español' },{ code:'fr', label:'Français' },
  { code:'de', label:'Deutsch' },{ code:'it', label:'Italiano' },{ code:'pt-BR', label:'Português (Brasil)' },
  { code:'zh', label:'中文 (简体)' },{ code:'ja', label:'日本語' },{ code:'ko', label:'한국어' },{ code:'ru', label:'Русский' },
];
